import numpy as np
from scipy.stats import ks_2samp

class LLMDriftMonitor:
    def __init__(self, reference_window_size=10_000):
        self.reference = []          # baseline output metrics
        self.current = []            # recent output metrics
        self.window_size = reference_window_size

    def log_response(self, prompt: str, response: str, latency_ms: float):
        metrics = {
            "output_length": len(response.split()),
            "latency_ms": latency_ms,
            "contains_refusal": self._is_refusal(response),
            "prompt_length": len(prompt.split()),
        }
        self.current.append(metrics)
        if len(self.current) > self.window_size:
            self.current.pop(0)

    def check_drift(self) -> dict:
        if len(self.reference) < 100 or len(self.current) < 100:
            return {"status": "insufficient_data"}

        results = {}
        for metric in ["output_length", "latency_ms", "prompt_length"]:
            ref_vals = [m[metric] for m in self.reference[-1000:]]
            cur_vals = [m[metric] for m in self.current[-1000:]]
            stat, p_value = ks_2samp(ref_vals, cur_vals)
            results[metric] = {"drift_detected": p_value < 0.01, "p_value": p_value}

        return results

    def _is_refusal(self, response: str) -> bool:
        refusal_phrases = ["I cannot", "I'm not able to", "I apologize, but"]
        return any(phrase in response for phrase in refusal_phrases)
